+
+        // 40 steady samples: 100 bytes consumed per 30-second interval.
+        for i in 1..=40u64 {
+            let free = total_free - i * 100;
+            let time = t0 + Duration::from_secs(i * 30);
+            let _ = estimator.update(free, time, threshold);
+        }
+
+        let steady_estimate = estimator.update(
