+        let steady_rate = steady_estimate.bytes_per_second;
+
+        // Now inject a massive burst: 500_000 bytes consumed in 30 seconds (50x spike).
+        let burst_free = total_free - 41 * 100 - 500_000;
+        let burst_estimate = estimator.update(
